import type CIMFilteredFindPathsEntity from "./CIMFilteredFindPathsEntity.js";
import type CIMFilteredFindPathsPathFilter from "./CIMFilteredFindPathsPathFilter.js";
import type CIMKGTraversalDirection from "./CIMKGTraversalDirection.js";
import type { JSONSupport } from "../../../../core/JSONSupport.js";
import type { CIMFilteredFindPathsEntityProperties } from "./CIMFilteredFindPathsEntity.js";
import type { CIMFilteredFindPathsPathFilterProperties } from "./CIMFilteredFindPathsPathFilter.js";
import type { CIMKGTraversalDirectionProperties } from "./CIMKGTraversalDirection.js";

export interface CIMFilteredFindPathsConfigurationProperties extends Partial<Pick<CIMFilteredFindPathsConfiguration, "defaultTraversalDirectionType" | "entityUsage" | "maxCountPaths" | "maxPathLength" | "minPathLength" | "name" | "pathMode">> {
  /** The [entities](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsEntity/) to use as the destination of the path. */
  destinationEntities?: CIMFilteredFindPathsEntityProperties[];
  /** The [entities](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsEntity/) to use as the origin of the paths. */
  originEntities?: CIMFilteredFindPathsEntityProperties[];
  /** Any [filters](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsPathFilter/) to use during pathfinding. */
  pathFilters?: CIMFilteredFindPathsPathFilterProperties[];
  /**
   * The filtered find paths algorithm uses traversal directions to specify how relationships are traversed.
   *  When no traversal direction is defined for a specific relationship type, the default traversal direction is used.
   */
  traversalDirections?: CIMKGTraversalDirectionProperties[];
}

/**
 * The pathfinding configuration for [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths)
 * and [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous).
 *
 *
 * You can define filters that specify which entity types and relationship types must be included.
 * You can also define filters that exclude entity types and relationship types or specific entities and relationships.
 * You can define mandatory waypoints (individual entities or relationships) that must be present in paths.
 * You can also define optional waypoints (individual entities or relationships, and entire entity types and entire relationship types):
 * when optional waypoints are defined, paths must pass through at least one of the optional waypoints.
 *
 * @beta
 * @since 4.32
 * @example
 * knowledgeGraphService.executeFindPaths({
 *     inKnowledgeGraphUrl: "https://sampleserver7.arcgisonline.com/server/rest/services/Hosted/BumbleBees/KnowledgeGraphServer",
 *     config: {
 * 			type: "CIMFilteredFindPathsConfiguration",
 * 			name: "exampleFFPconfiguration",
 * 			originEntities: [
 * 				{
 * 					type: "CIMFilteredFindPathsEntity",
 * 					iD: devPathStart,
 * 					entityTypeName: "User"
 * 				}
 * 			],
 * 			destinationEntities: [
 * 				{
 * 					type: "CIMFilteredFindPathsEntity",
 * 					iD: devPathEnd,
 * 					entityTypeName: "Species"
 * 				}
 * 			],
 * 			pathFilters: [
 * 				{
 * 					type: "CIMFilteredFindPathsPathFilter",
 * 					iD: null,
 * 					itemTypeName: "Observation",
 * 					itemType: "Entity",
 * 					filterType: "Include"
 * 				}
 * 			],
 * 			defaultTraversalDirectionType: "Any",
 * 			entityUsage: "EachPair",
 * 			pathMode: "All",
 * 			minPathLength: 1,
 * 			maxPathLength: 8,
 * 			maxCountPaths: 100000
 * 		}
 *   });
 */
export default class CIMFilteredFindPathsConfiguration extends JSONSupport {
  constructor(properties?: CIMFilteredFindPathsConfigurationProperties);
  /**
   * Specifies the direction which the algorithm uses to traverse relationship in the path.
   *  |Direction| Description|
   * |---------|------------|
   * |Any|The filtered find paths algorithm considers all relationships independent of their direction.|
   * |Forward|The filtered find paths algorithm considers only the relationships that are traversed in forward direction, `origin --> destination`. |
   * |Backward|The filtered find paths algorithm considers only the relationships that are traversed in backward direction, `origin <-- destination`.|
   *
   * @default "Any"
   */
  accessor defaultTraversalDirectionType: TraversalDirectionType;
  /** The [entities](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsEntity/) to use as the destination of the path. */
  get destinationEntities(): CIMFilteredFindPathsEntity[];
  set destinationEntities(value: CIMFilteredFindPathsEntityProperties[]);
  /**
   * Specifies how the origin and destination entities are used in the [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths) and [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous) algorithm.
   * For example, say you want to find all shortest paths between {A, B} and {C, D} where A and B are your possible origin entities and
   *  C and D are your possible destination entities.
   * Using the default setting of `AnyOriginAnyDestination`, this means that the algorithm can return 4 kinds of shortest paths:
   *
   * A -> C
   *
   * A -> D
   *
   * B -> C
   *
   * B -> D
   *
   * If the shortest paths between each origin and each destination have the following lengths:
   *
   * A -> C : length 4
   *
   * A -> D : length 3
   *
   * B -> C : length 5
   *
   * B -> D : length 6
   *
   * Then the "shortest shortest paths" here are the shortest paths of length 3, from A to D.
   * So only these paths will be returned.
   *
   * |Option |Description|
   * |-------|-----------|
   * | AnyOriginAnyDestination|  The filtered find paths algorithm only returns the shortest paths for the origin entities that have the shortest shortest paths and the shortest paths for the destination entities that have the shortest shortest paths. When multiple entities are used, this option leads to faster computations.|
   * | AnyOriginAllDestinations|  The filtered find paths algorithm returns the shortest paths for the origin entities that have the shortest shortest paths and one shortest path (if it exists) per destination entity. When multiple entities are used, this option leads to longer computations.|
   * | AllOriginsAnyDestination| The filtered find paths algorithm returns one shortest path (if it exists) per origin entity and the shortest paths for the destination entities that have the shortest shortest paths. When multiple entities are used, this option leads to longer computations.|
   * | AllOriginsAllDestinations| The filtered find paths algorithm returns one shortest path (if it exists) per origin entity and one shortest path (if it exists) per destination entity. When multiple entities are used, this option leads to longer computations.|
   * | EachPair| The filtered find paths algorithm returns one shortest path (if it exists) per pair of origin and destination entity. When multiple entities are used, this option leads to longer computations. An error will be returned if strictly more than 10 origin entities are defined or if strictly more than 10 destination entities are defined.|
   *
   * @default "AnyOriginAnyDestination"
   */
  accessor entityUsage: FilteredFindPathsEntityUsageType;
  /**
   * The maximum number of paths that the [executeFindPaths()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPaths) and [executeFindPathsAsynchronous()](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraphService/#executeFindPathsAsynchronous)
   * algorithm returns. This parameter is only taken into account when [pathMode](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsConfiguration/#pathMode) is `All`.
   *
   * @default 100000
   */
  accessor maxCountPaths: number;
  /**
   * The maximum path length. The default value of `0` means the value is unlimited.
   *
   * @default 0
   */
  accessor maxPathLength: number;
  /**
   * The minimum path length.
   *
   * @default 1
   */
  accessor minPathLength: number;
  /**
   * The name of the configuration.
   *
   * @default ""
   */
  accessor name: string;
  /** The [entities](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsEntity/) to use as the origin of the paths. */
  get originEntities(): CIMFilteredFindPathsEntity[];
  set originEntities(value: CIMFilteredFindPathsEntityProperties[]);
  /** Any [filters](https://developers.arcgis.com/javascript/latest/references/core/rest/knowledgeGraph/toolService/findPaths/CIMFilteredFindPathsPathFilter/) to use during pathfinding. */
  get pathFilters(): CIMFilteredFindPathsPathFilter[];
  set pathFilters(value: CIMFilteredFindPathsPathFilterProperties[]);
  /**
   * Specifies whether the filtered find paths algorithm searches for all paths or only the shortest paths.
   *
   * @default "Shortest"
   */
  accessor pathMode: "Shortest" | "All";
  /**
   * The filtered find paths algorithm uses traversal directions to specify how relationships are traversed.
   *  When no traversal direction is defined for a specific relationship type, the default traversal direction is used.
   */
  get traversalDirections(): CIMKGTraversalDirection[];
  set traversalDirections(value: CIMKGTraversalDirectionProperties[]);
  get type(): "CIMFilteredFindPathsConfiguration";
}

export type FilteredFindPathsEntityUsageType = "AnyOriginAnyDestination" | "AnyOriginAllDestinations" | "AllOriginsAnyDestination" | "AllOriginsAllDestinations" | "EachPair";

export type TraversalDirectionType = "Any" | "Forward" | "Backward";